SELECT instance_type_name, description, category
FROM instance_types_historic
WHERE expiration_date IS NULL;

SELECT report_name
FROM reporting
ORDER BY report_date DESC;

SELECT SUM(memory_gb) AS total_memory_gb
FROM instance_types_historic
WHERE instance_type_name = 'Large';

SELECT instance_type_name
FROM instance_types_historic
WHERE memory_gb = (SELECT MAX(memory_gb) FROM instance_types_historic);

SELECT instance_type_name
FROM instance_types_historic
WHERE instance_type_id IN (
  SELECT json_extract(report_data, '$.instance_types[0].instance_type_id') AS instance_type_id
  FROM reporting
);

SELECT instance_type_name, vcpu, memory_gb
     FROM instance_types_historic
     ORDER BY vcpu DESC;

SELECT instance_type_name
FROM instance_types_historic
WHERE instance_type_id = 0;

SELECT instance_type_id, MIN(effective_date) AS earliest_effective_date
FROM instance_types_historic
GROUP BY instance_type_id;
